//! Build script for baton-rs.
//!
//! Two pipelines run here:
//!
//! 1. **bindgen** generates raw FFI bindings from `wrapper.h` (which
//!    transitively includes the iRODS client headers) into
//!    `$OUT_DIR/bindings.rs`, and emits link directives for the iRODS
//!    client library. `src/ffi.rs` includes the generated file.
//!
//! 2. **cc** compiles `shim/ffi_shim.c` into a static library that the
//!    Rust crate links against. The shim is the version-agnostic API
//!    layer being built up over Session 4.5 (issue #9). At this stage
//!    it has no functions yet — the build pipeline is in place so each
//!    subsystem migration in subsequent commits can drop a function in
//!    without further build-system churn.

use std::env;
use std::path::PathBuf;

fn main() {
    println!("cargo:rerun-if-changed=build.rs");
    println!("cargo:rerun-if-changed=wrapper.h");
    println!("cargo:rerun-if-changed=shim/ffi_shim.c");
    println!("cargo:rerun-if-changed=shim/ffi_shim.h");

    // Compile the C shim into libbaton_rs_shim.a and emit the static-link
    // directive. iRODS headers are made available so the shim can call
    // through to them as functions are added in later commits — the shim
    // is the only TU that #includes them at the point we narrow bindgen.
    cc::Build::new()
        .file("shim/ffi_shim.c")
        .include("shim")
        .include("/usr/include/irods")
        .warnings(true)
        .compile("baton_rs_shim");

    // Link dynamically against the iRODS client libraries provided by the
    // iRODS .deb packages (decision recorded in Project constants).
    //
    // iRODS splits its client runtime across at least two shared objects:
    //   - libirods_client — connection/protocol APIs (rcConnect, clientLogin, …)
    //   - libirods_common — utilities, including getRodsEnv
    // If more symbols surface as undefined later, switch to pkg-config.
    println!("cargo:rustc-link-lib=irods_client");
    println!("cargo:rustc-link-lib=irods_common");

    let bindings = bindgen::Builder::default()
        .header("wrapper.h")
        .clang_arg("-I/usr/include/irods")
        // Shim functions / types — the version-agnostic C surface from
        // `shim/ffi_shim.h`. Every subsystem migrated in Session 4.5
        // calls these instead of the raw iRODS API. The opaque
        // `shim_rods_conn` forward declaration is allowlisted as a type
        // so Rust can hold a `*mut ffi::shim_rods_conn` without bindgen
        // ever seeing the underlying `rcComm_t` definition.
        .allowlist_function("shim_.*")
        .allowlist_type("shim_env_t")
        .allowlist_type("shim_stat_t")
        .allowlist_type("shim_rods_conn")
        // iRODS functions still called directly by not-yet-migrated
        // subsystems. Each batch moves behind the shim in subsequent
        // commits (queries, metamod, error-name lookup), at which point
        // its entry here goes away.
        .allowlist_function("clientLogin")
        .allowlist_function("rErrMsg")
        .allowlist_function("rodsErrorName")
        // General catalog query — every metadata flag (--avu / --acl /
        // --replicate / --timestamp) goes through rcGenQuery.
        .allowlist_function("rcGenQuery")
        .allowlist_function("addInxIval")
        .allowlist_function("addInxVal")
        .allowlist_function("clearGenQueryInp")
        .allowlist_function("freeGenQueryOut")
        // AVU add/remove — baton-metamod's only iRODS call. iRODS encodes
        // the operation via positional arg0..arg9 strings on the input
        // struct (arg0=operation, arg1=target-type-flag, arg2=path, etc.);
        // the safe wrapper hides that stringly-typed shape.
        .allowlist_function("rcModAVUMetadata")
        // Types referenced by the iRODS functions still called directly.
        .allowlist_type("rcComm_t")
        .allowlist_type("rErrMsg_t")
        .allowlist_type("modAVUMetadataInp_t")
        .allowlist_type("genQueryInp_t")
        .allowlist_type("genQueryOut_t")
        .allowlist_type("sqlResult_t")
        .allowlist_type("inxIvalPair_t")
        .allowlist_type("inxValPair_t")
        // Error code constants used when translating iRODS codes into
        // BatonError. The allowlist is broad on purpose — constants are cheap.
        .allowlist_var("CAT_.*")
        .allowlist_var("SYS_.*")
        .allowlist_var("AUTH_.*")
        .allowlist_var("USER_.*")
        // Catalog column numeric indices used in SELECT / WHERE.
        .allowlist_var("COL_.*")
        .parse_callbacks(Box::new(bindgen::CargoCallbacks::new()))
        .generate()
        .expect("bindgen: failed to generate iRODS bindings");

    let out_path = PathBuf::from(env::var("OUT_DIR").unwrap());
    bindings
        .write_to_file(out_path.join("bindings.rs"))
        .expect("bindgen: failed to write bindings.rs");
}
